function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
    const validCoupons: {order: number, code: string}[] = [];
    const businessOrder: {[key: string]: number} = {
        "electronics": 0,
        "grocery": 1,
        "pharmacy": 2,
        "restaurant": 3
    };

    for (let i = 0; i < code.length; i++) {
        // Check condition 1: code is not empty and only contains alphanumeric or underscore
        if (!code[i] || !/^[a-zA-Z0-9_]+$/.test(code[i])) {
            continue;
        }

        // Check condition 2: businessLine is one of the allowed categories
        if (!(businessLine[i] in businessOrder)) {
            continue;
        }

        // Check condition 3: isActive is true
        if (!isActive[i]) {
            continue;
        }

        validCoupons.push({
            order: businessOrder[businessLine[i]],
            code: code[i]
        });
    }

    // Sort by business order first, then by code lexicographically
    validCoupons.sort((a, b) => {
        if (a.order !== b.order) {
            return a.order - b.order;
        }
        return a.code.localeCompare(b.code);
    });

    return validCoupons.map(coupon => coupon.code);
}
